import { useParams, Link } from "react-router-dom";
import { useState, useEffect } from "react";
import Card from "../components/Card";

export default function RoadmapPage() {
  const { name } = useParams();

  const domainKey =
    (name || localStorage.getItem("selectedDomain") || "ai-and-ml").toLowerCase();

  if (name) {
    localStorage.setItem("selectedDomain", domainKey);
  }

  const timeline = localStorage.getItem("timeline") || "3 months";
  const totalDays = parseInt(timeline) * 30;

  const currentDay = parseInt(localStorage.getItem("currentDay") || "1");

  // 🔥 STATE FLAGS
  const [journeyStarted, setJourneyStarted] = useState(false);
  const [learningStarted, setLearningStarted] = useState(false);

  useEffect(() => {
    setJourneyStarted(localStorage.getItem("journeyStarted") === "true");
    setLearningStarted(localStorage.getItem("learningStarted") === "true");
  }, []);

  // 🔥 TOPICS
  const topicMap = {
    "ai-and-ml": [
      ["Python Basics → Datatypes"],
      ["Variables & Input/Output"],
      ["Loops", "Conditions"],
      ["Functions"],
      ["NumPy"],
      ["Pandas"],
      ["Visualization"],
      ["Statistics"],
      ["ML Algorithms"],
      ["Deep Learning"],
      ["Neural Networks"],
      ["Project"]
    ]
  };

  const topics = topicMap[domainKey] || [["Basics"]];

  const getTasksForDay = (day) => {
    const index = (day - 1) % topics.length;
    return topics[index];
  };

  // 🔥 BUTTON HANDLERS
  const handleStartJourney = () => {
    localStorage.setItem("journeyStarted", "true");
    setJourneyStarted(true);
  };

  const handleStartToday = () => {
    localStorage.setItem("learningStarted", "true");
    localStorage.setItem("currentDay", 1);
    localStorage.setItem("carryForward", "[]");
    setLearningStarted(true);
  };

  // 🔥 PROGRESS
  const progress = Math.min((currentDay / totalDays) * 100, 100);

  // 🔥 STREAK
  const streak = localStorage.getItem("streak") || 0;

  // 🔥 CALENDAR
  const completedDays = JSON.parse(localStorage.getItem("completedDays") || "[]");

  return (
    <div className="space-y-8">
      <Card title="Learning Roadmap">

        {/* 📊 PROGRESS BAR */}
        <div className="mb-4">
          <div className="w-full bg-gray-200 rounded-full h-3">
            <div
              className="bg-teal-500 h-3 rounded-full"
              style={{ width: `${progress}%` }}
            ></div>
          </div>
          <p className="text-sm mt-1">{Math.floor(progress)}% completed</p>
        </div>

        {/* 🔥 STREAK */}
        <p className="text-sm mb-4">🔥 Streak: {streak} days</p>

        {/* STEP 1 */}
        {!journeyStarted && (
          <div className="space-y-4 text-center">

            <h3 className="text-xl font-semibold">
              🚀 Your Learning Journey
            </h3>

            <p className="text-gray-600">
              Topics you will learn:
            </p>

            <div className="grid gap-3">
              {topics.map((t, i) => (
                <div key={i} className="p-3 bg-green-100 rounded-lg">
                  {t.join(", ")}
                </div>
              ))}
            </div>

            <button
              onClick={handleStartJourney}
              className="mt-4 px-6 py-3 bg-teal-500 text-white rounded-xl"
            >
              Start Journey 🚀
            </button>

          </div>
        )}

        {/* STEP 2 */}
        {journeyStarted && !learningStarted && (
          <div className="text-center space-y-4">

            <h3 className="text-xl font-semibold">
              Ready to begin?
            </h3>

            <button
              onClick={handleStartToday}
              className="px-6 py-3 bg-teal-600 text-white rounded-xl"
            >
              Start From Today 📅
            </button>

          </div>
        )}

        {/* STEP 3 */}
        {learningStarted && (
          <div className="space-y-4">

            <h3 className="text-lg font-semibold">
              📅 Day {currentDay} Plan
            </h3>

            <div className="space-y-2">
              {getTasksForDay(currentDay).map((task, i) => (
                <div key={i} className="p-4 bg-green-100 rounded-lg">
                  {task}
                </div>
              ))}
            </div>

            <Link to="/tasks">
              <button className="mt-4 px-4 py-2 bg-teal-500 text-white rounded-lg">
                Go to Tasks →
              </button>
            </Link>

          </div>
        )}

        {/* 📅 CALENDAR */}
        <div className="mt-8">
          <h3 className="text-lg font-semibold mb-2">📅 Progress Calendar</h3>

          <div className="grid grid-cols-7 gap-2">
            {Array.from({ length: totalDays }).map((_, i) => {
              const day = i + 1;

              return (
                <div
                  key={day}
                  className={`p-2 text-center rounded text-xs ${
                    completedDays.includes(day)
                      ? "bg-teal-400 text-white"
                      : "bg-gray-200"
                  }`}
                >
                  {day}
                </div>
              );
            })}
          </div>
        </div>

      </Card>
    </div>
  );
}
